import{_ as i,o as t,c as e,ag as s}from"./chunks/framework.uOkKsJ4G.js";const c=JSON.parse('{"title":"快速开始","description":"5 分钟完成 Narrafiilm 安装与首次第一人称视频解说生成。","frontmatter":{"title":"快速开始","description":"5 分钟完成 Narrafiilm 安装与首次第一人称视频解说生成。"},"headers":[],"relativePath":"guide/quick-start.md","filePath":"guide/quick-start.md","lastUpdated":1775974440000}'),l={name:"guide/quick-start.md"};function n(r,a,h,o,d,p){return t(),e("div",null,[...a[0]||(a[0]=[s(`<h1 id="快速开始" tabindex="-1">快速开始 <a class="header-anchor" href="#快速开始" aria-label="Permalink to &quot;快速开始&quot;">​</a></h1><blockquote><p>⏱️ 预计时间：5 分钟（已安装应用者 2 分钟）</p></blockquote><hr><h2 id="系统要求" tabindex="-1">系统要求 <a class="header-anchor" href="#系统要求" aria-label="Permalink to &quot;系统要求&quot;">​</a></h2><table tabindex="0"><thead><tr><th>项目</th><th>最低要求</th><th>推荐</th></tr></thead><tbody><tr><td>操作系统</td><td>Windows 10+ / macOS 11+ / Ubuntu 20.04+</td><td>Windows 11 / macOS 13+</td></tr><tr><td>内存</td><td>8 GB</td><td>16 GB</td></tr><tr><td>显卡</td><td>—</td><td>NVIDIA 4GB+（CUDA 加速）</td></tr><tr><td>存储</td><td>2 GB</td><td>10 GB（包含模型缓存）</td></tr><tr><td>网络</td><td>用于调用 AI API</td><td>—</td></tr></tbody></table><hr><h2 id="下载与安装" tabindex="-1">下载与安装 <a class="header-anchor" href="#下载与安装" aria-label="Permalink to &quot;下载与安装&quot;">​</a></h2><p>###方式一：安装包（推荐）</p><ol><li>打开 <a href="https://github.com/Agions/Narrafiilm/releases/latest" target="_blank" rel="noreferrer">GitHub Releases</a></li><li>下载对应平台版本：</li></ol><table tabindex="0"><thead><tr><th>平台</th><th>文件名</th></tr></thead><tbody><tr><td>Windows</td><td><code>Narrafiilm-Setup-x.x.x.exe</code></td></tr><tr><td>macOS</td><td><code>Narrafiilm-x.x.x.dmg</code></td></tr><tr><td>Linux</td><td><code>Narrafiilm-x.x.x.AppImage</code></td></tr></tbody></table><ol start="3"><li>运行安装包，按提示完成</li></ol><h3 id="方式二-homebrew-macos-linux" tabindex="-1">方式二：Homebrew（macOS / Linux） <a class="header-anchor" href="#方式二-homebrew-macos-linux" aria-label="Permalink to &quot;方式二：Homebrew（macOS / Linux）&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">brew</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> agions/tap/narrafiilm</span></span></code></pre></div><h3 id="方式三-源码安装" tabindex="-1">方式三：源码安装 <a class="header-anchor" href="#方式三-源码安装" aria-label="Permalink to &quot;方式三：源码安装&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clone</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://github.com/Agions/Narrafiilm.git</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> narrafiilm</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">python</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -m</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> venv</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> venv</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &amp;&amp; </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">source</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> venv/bin/activate</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  # Windows: venv\\Scripts\\activate</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pip</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -r</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> requirements.txt</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">python</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> app/main.py</span></span></code></pre></div><blockquote><p>⚠️ 源码安装需要自行安装 <a href="https://ffmpeg.org/download.html" target="_blank" rel="noreferrer">FFmpeg</a>。</p></blockquote><hr><h2 id="配置-api-key" tabindex="-1">配置 API Key <a class="header-anchor" href="#配置-api-key" aria-label="Permalink to &quot;配置 API Key {#配置-api-key}&quot;">​</a></h2><p>Narrafiilm 需要一个 AI API Key 来生成解说词。<strong>DeepSeek</strong> 性价比最高，每月约 $1 可处理数十个视频。</p><h3 id="获取-deepseek-api-key" tabindex="-1">获取 DeepSeek API Key <a class="header-anchor" href="#获取-deepseek-api-key" aria-label="Permalink to &quot;获取 DeepSeek API Key&quot;">​</a></h3><ol><li>打开 <a href="https://platform.deepseek.com" target="_blank" rel="noreferrer">platform.deepseek.com</a></li><li>注册并登录</li><li>进入 <strong>API Keys</strong> → <strong>Create API Key</strong></li><li>复制生成的 Key（格式：<code>sk-...</code>）</li></ol><h3 id="填入应用" tabindex="-1">填入应用 <a class="header-anchor" href="#填入应用" aria-label="Permalink to &quot;填入应用&quot;">​</a></h3><p>启动 Narrafiilm → <strong>设置</strong> → <strong>AI 配置</strong> → 粘贴 Key → <strong>保存</strong></p><p>或直接编辑项目根目录的 <code>.env</code> 文件：</p><div class="language-env vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">env</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>DEEPSEEK_API_KEY=sk-xxxxxxxxxxxxxxxxxxxxxxxx</span></span></code></pre></div><h3 id="验证连接" tabindex="-1">验证连接 <a class="header-anchor" href="#验证连接" aria-label="Permalink to &quot;验证连接&quot;">​</a></h3><p>进入 <strong>设置 → AI 配置</strong>，点击 <strong>连接测试</strong>。出现 ✅ 即表示配置成功。</p><hr><h2 id="创建第一个解说视频-3-步" tabindex="-1">创建第一个解说视频（3 步） <a class="header-anchor" href="#创建第一个解说视频-3-步" aria-label="Permalink to &quot;创建第一个解说视频（3 步）&quot;">​</a></h2><h3 id="第-1-步-新建项目" tabindex="-1">第 1 步：新建项目 <a class="header-anchor" href="#第-1-步-新建项目" aria-label="Permalink to &quot;第 1 步：新建项目&quot;">​</a></h3><p>启动应用 → 点击 <strong>新建项目</strong> → 选择保存位置 → 输入项目名称</p><h3 id="第-2-步-导入视频" tabindex="-1">第 2 步：导入视频 <a class="header-anchor" href="#第-2-步-导入视频" aria-label="Permalink to &quot;第 2 步：导入视频&quot;">​</a></h3><ul><li>点击 <strong>导入素材</strong> 按钮，或直接将视频文件拖入窗口</li><li>支持格式：<code>MP4</code> / <code>MOV</code> / <code>AVI</code> / <code>MKV</code> / <code>WebM</code></li></ul><h3 id="第-3-步-生成解说" tabindex="-1">第 3 步：生成解说 <a class="header-anchor" href="#第-3-步-生成解说" aria-label="Permalink to &quot;第 3 步：生成解说&quot;">​</a></h3><ol><li>确认视频已加载</li><li>选择<strong>情感风格</strong>：治愈 / 悬疑 / 励志 / 怀旧 / 浪漫</li><li>选择<strong>配音音色</strong>：默认 XiaoXiao（女声）</li><li>点击 <strong>开始创作</strong></li></ol><p>等待 AI 完成处理（通常 1–3 分钟，取决于视频长度和 API 速度），预览结果后点击 <strong>导出</strong>。</p><hr><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><h3 id="提示-ffmpeg-not-found" tabindex="-1">提示 &quot;FFmpeg not found&quot; <a class="header-anchor" href="#提示-ffmpeg-not-found" aria-label="Permalink to &quot;提示 &quot;FFmpeg not found&quot;&quot;">​</a></h3><p>FFmpeg 是视频处理的核心依赖，未安装会导致所有视频操作失败。</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># macOS</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">brew</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ffmpeg</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Ubuntu / Debian</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> apt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ffmpeg</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Windows</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 下载 https://www.gyan.dev/ffmpeg/builds/ ，解压后将 bin 目录加入 PATH</span></span></code></pre></div><p>安装后重启应用。</p><h3 id="ai-功能报错-401-403" tabindex="-1">AI 功能报错 401 / 403 <a class="header-anchor" href="#ai-功能报错-401-403" aria-label="Permalink to &quot;AI 功能报错 401 / 403&quot;">​</a></h3><p>API Key 无效或额度用尽。进入 <a href="https://platform.deepseek.com" target="_blank" rel="noreferrer">platform.deepseek.com</a> 检查 Key 状态和账户余额。</p><h3 id="处理速度很慢" tabindex="-1">处理速度很慢 <a class="header-anchor" href="#处理速度很慢" aria-label="Permalink to &quot;处理速度很慢&quot;">​</a></h3><ul><li>确认网络连接稳定（调用外部 API）</li><li>有 NVIDIA 显卡时自动启用 CUDA 加速</li><li>减少抽帧密度可提速（设置 → 场景理解 → 抽帧间隔）</li></ul><h3 id="显存不足-oom" tabindex="-1">显存不足（OOM） <a class="header-anchor" href="#显存不足-oom" aria-label="Permalink to &quot;显存不足（OOM）&quot;">​</a></h3><p>GPU 模式对显存要求较高。进入 <strong>设置 → AI 配置</strong>，关闭 <strong>启用 GPU 加速</strong>，回退到 CPU 模式。</p><h3 id="无-display-环境运行静默退出" tabindex="-1">无 DISPLAY 环境运行静默退出 <a class="header-anchor" href="#无-display-环境运行静默退出" aria-label="Permalink to &quot;无 DISPLAY 环境运行静默退出&quot;">​</a></h3><p>Linux 无头环境（SSH / 服务器）下，应用会自动设置 <code>QT_QPA_PLATFORM=offscreen</code>，无需额外配置。</p><hr><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><ul><li><a href="./../features.html">功能详细介绍</a> — 情感风格、字幕样式、导出格式详解</li><li><a href="./../guide/installation.html">完整安装指南</a> — 各平台依赖、CUDA 配置、F5-TTS 安装</li><li><a href="./../faq.html">常见问题</a> — 更多问题解答</li></ul>`,53)])])}const g=i(l,[["render",n]]);export{c as __pageData,g as default};
